import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.VxKNwi4m.js";const f=JSON.parse('{"title":"정산 현황 관리","description":"","frontmatter":{},"headers":[],"relativePath":"ledger/status.md","filePath":"ledger/status.md","lastUpdated":1783990812000}'),i={name:"ledger/status.md"};function n(o,t,s,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="정산-현황-관리" tabindex="-1">정산 현황 관리 <a class="header-anchor" href="#정산-현황-관리" aria-label="Permalink to &quot;정산 현황 관리&quot;">​</a></h1><p>프로젝트의 실시간 자금 현황, 당일 입출금 내역 및 예산 대비 집행 실적을 통합적으로 조회하고 관리하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>회계 자금 관리 &gt; 정산 현황 관리</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>특정 <strong>기준일자</strong>를 중심으로 프로젝트의 현금성 자산 상태와 예산 집행 현황을 분석합니다. 은행 계좌별 잔액 현황, 일자별 상세 거래 내역, 그리고 사업비 예산 대비 실제 지출액을 대조하여 프로젝트의 재무 건전성을 파악할 수 있습니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li><strong>기준일자별 조회</strong>: 원하는 날짜를 지정하여 과거 특정 시점의 정산 보고서 생성</li><li><strong>계좌별 자금 관리</strong>: 전일 잔액, 당일 증감, 현재 잔액의 실시간 동기화</li><li><strong>일일 입출금 보고</strong>: 당일 발생한 입/출금 건별 적요 및 계정 과목 상세 내역 확인</li><li><strong>예산 집행 분석</strong>: 기초/현황 예산 대비 누적 집행액 및 잔여 예산 모니터링</li><li><strong>데이터 내보내기</strong>: 각 탭별 현황 엑셀 다운로드 및 정식 캐시플로우(Cash Flow) 폼 출력</li><li><strong>최종 정산 확인</strong>: 실제 은행 잔고와 시스템 장부 금액의 일치 여부 최종 확정</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-기준일자-및-탭-선택" tabindex="-1">1. 기준일자 및 탭 선택 <a class="header-anchor" href="#_1-기준일자-및-탭-선택" aria-label="Permalink to &quot;1. 기준일자 및 탭 선택&quot;">​</a></h3><ul><li><strong>기준일자</strong>: 모든 데이터 집계의 기준이 되는 날짜를 선택합니다.</li><li><strong>보고서 탭</strong>: [계좌별 자금현황], [당일 입출금내역], [예산대비 집계] 중 원하는 리포트를 선택합니다.</li></ul><h3 id="_2-계좌별-자금현황-탭" tabindex="-1">2. 계좌별 자금현황 (탭) <a class="header-anchor" href="#_2-계좌별-자금현황-탭" aria-label="Permalink to &quot;2. 계좌별 자금현황 (탭)&quot;">​</a></h3><p>프로젝트가 보유한 보통예금 계좌들의 잔액 변화를 보여줍니다.</p><h4 id="주요-표시-항목" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">항목</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;">전일잔고</td><td style="text-align:left;">기준일자 이전까지의 누적 잔액</td></tr><tr><td style="text-align:left;">금일입금(증가)</td><td style="text-align:left;">기준일 당일 입금된 금액의 합계</td></tr><tr><td style="text-align:left;">금일출금(감소)</td><td style="text-align:left;">기준일 당일 출금된 금액의 합계</td></tr><tr><td style="text-align:left;">금일잔고</td><td style="text-align:left;">전일잔고 + 당일입금 - 당일출금 결과 (실제 현재 잔고)</td></tr></tbody></table><ul><li><strong>필터</strong>: &#39;잔고 존재 계좌만 보기&#39; 또는 &#39;직불 용역비 계좌 포함&#39; 옵션을 제공합니다.</li></ul><h3 id="_3-당일-입출금내역-탭" tabindex="-1">3. 당일 입출금내역 (탭) <a class="header-anchor" href="#_3-당일-입출금내역-탭" aria-label="Permalink to &quot;3. 당일 입출금내역 (탭)&quot;">​</a></h3><p>기준일에 발생한 개별 거래의 상세 정보를 입금과 출금으로 나누어 표시합니다.</p><ul><li><strong>표시 정보</strong>: 거래 계좌, 적요(내용), 금액, 연결된 계정과목 및 거래처 정보</li></ul><h3 id="_4-예산대비-집계-탭" tabindex="-1">4. 예산대비 집계 (탭) <a class="header-anchor" href="#_4-예산대비-집계-탭" aria-label="Permalink to &quot;4. 예산대비 집계 (탭)&quot;">​</a></h3><p>사업비 항목별 예산과 실제 집행 실적을 대조합니다.</p><h4 id="주요-표시-항목-1" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목-1" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">항목</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;">예산 금액</td><td style="text-align:left;">선택에 따라 &#39;기초 예산&#39; 또는 &#39;현황 예산&#39; 표시 (현황 예산은 이 화면에서 즉시 수정 가능)</td></tr><tr><td style="text-align:left;">전월 집행 누계</td><td style="text-align:left;">당월 이전까지 집행된 금액의 총합</td></tr><tr><td style="text-align:left;">당월 집행 금액</td><td style="text-align:left;">이번 달에 집행된 금액</td></tr><tr><td style="text-align:left;">집행금액 합계</td><td style="text-align:left;">현재까지의 총 누적 집행액</td></tr><tr><td style="text-align:left;">가용 예산 합계</td><td style="text-align:left;">예산 금액 - 집행금액 합계 (잔여 예산)</td></tr></tbody></table><ul><li><strong>캐시플로우 폼</strong>: 상단의 버튼을 통해 월별 자금 집행 현황이 포함된 표준 엑셀 서식을 다운로드할 수 있습니다.</li></ul><h3 id="_5-최종-정산-확정-하단" tabindex="-1">5. 최종 정산 확정 (하단) <a class="header-anchor" href="#_5-최종-정산-확정-하단" aria-label="Permalink to &quot;5. 최종 정산 확정 (하단)&quot;">​</a></h3><p>모든 입출금 내역을 확인한 후, 시스템 상의 장부 잔액을 최종 확정(Check Balance)하는 기능입니다.</p><ul><li><strong>상태 표시</strong>: 마지막 거래일자와 시스템 정산일자를 비교하여 정산 필요 여부를 안내합니다.</li></ul><h2 id="💡-활용-가이드" tabindex="-1">💡 활용 가이드 <a class="header-anchor" href="#💡-활용-가이드" aria-label="Permalink to &quot;💡 활용 가이드&quot;">​</a></h2><ul><li><strong>예산 수정</strong>: [예산대비 집계] 탭에서 &#39;현황 예산&#39;을 선택한 후 금액을 <strong>더블 클릭</strong>하면 프로젝트 설정 메뉴로 이동하지 않고도 즉시 예산 금액을 조정할 수 있습니다.</li><li><strong>일치 여부 확인</strong>: 매일 일과 종료 후 [계좌별 자금현황]의 &#39;금일잔고&#39; 합계와 실제 은행 앱의 잔액 합계를 대조하여 장부 누락 여부를 점검하는 것이 좋습니다.</li></ul>',28)])])}const c=e(i,[["render",n]]);export{f as __pageData,c as default};
